(function() {
  'use strict';

  tinymce.PluginManager.add('customscriptstyle', function(editor) {

    // Gera o HTML do indicador visual
    function getMarker(type) {
      var label = (type === 'script' ? 'Script' : 'Estilo') + ' personalizado';
      return '<div class="tmce-visual-hint" contenteditable="false" style="display:inline-block; background:#fef3c7; border:2px dashed #f59e0b; padding:6px 10px; cursor:pointer; font-family:monospace; font-size:12px; color:#92400e; margin:4px 2px; border-radius:4px; font-weight:bold;">🔧 ' + label + '</div>';
    }

    // 1. ANTES DE RENDERIZAR: Adiciona o indicador APÓS a tag real
    editor.on('BeforeSetContent', function(e) {
      e.content = e.content.replace(/<(script|style)\b([^>]*)>([\s\S]*?)<\/\1>/gi, function(match, type) {
        return match + getMarker(type);
      });
    });

    // 2. ANTES DE SALVAR: Remove apenas o indicador
    editor.on('GetContent', function(e) {
      if (e.format === 'html') {
        e.content = e.content.replace(/<div\b[^>]*class="tmce-visual-hint"[^>]*>.*?<\/div>/gi, '');
        // Limpa parágrafos vazios que podem sobrar
        e.content = e.content.replace(/<p>\s*(?:&nbsp;|\u00a0|\uFEFF)?\s*<\/p>/gi, '');
      }
    });

    // 3. CLIQUE no indicador: Abre editor de código
    editor.on('Click', function(e) {
      var node = editor.dom.getParent(e.target, 'div.tmce-visual-hint');
      if (node) {
        e.preventDefault();
        e.stopPropagation();
        editor.execCommand('mceCodeEditor');
      }
    });

    // 4. BOTÃO na toolbar: Insere tag real + indicador
    editor.ui.registry.addButton('customscriptstyle', {
      text: '[+ Script/Style]',
      tooltip: 'Inserir bloco de script ou estilo',
      onAction: function() {
        editor.windowManager.open({
          title: 'Inserir Script ou Estilo',
          body: {
            type: 'panel',
            items: [
              { type: 'listbox', name: 'type', label: 'Tipo', items: [{text: 'Script', value: 'script'}, {text: 'Estilo', value: 'style'}] },
              { type: 'input', name: 'attrs', label: 'Atributos (ex: src="url.js")', value: '' }
            ]
          },
          buttons: [
            { type: 'cancel', text: 'Cancelar' },
            { type: 'submit', text: 'Inserir', primary: true }
          ],
          onSubmit: function(api) {
            var data = api.getData();
            var tag = '<' + data.type + (data.attrs ? ' ' + data.attrs : '') + '></' + data.type + '>';
            editor.insertContent(tag + getMarker(data.type));
            api.close();
            // Já abre o código para preencher o conteúdo
            setTimeout(function() { editor.execCommand('mceCodeEditor'); }, 100);
          }
        });
      }
    });

    return {};
  });
})();
